  const [patients, setPatients] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // History State
  const [historyAdmissions, setHistoryAdmissions] = useState<any[]>([]);
  const [historyLoading, setHistoryLoading] = useState(false);
  const [historySearch, setHistorySearch] = useState('');
  const [historyFilterStatus, setHistoryFilterStatus] = useState('All');
  const [historyPage, setHistoryPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  // Modals
  const [reserveModalOpen, setReserveModalOpen] = useState(false);
  const [careModalOpen, setCareModalOpen] = useState(false);

  const [selectedBed, setSelectedBed] = useState<any>(null);
  const [selectedAdmission, setSelectedAdmission] = useState<any>(null);

  // Forms
  const [reserveForm, setReserveForm] = useState({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: 0, notes: '' });
  const [careTab, setCareTab] = useState<'overview' | 'notes' | 'discharge'>('overview');
  const [noteForm, setNoteForm] = useState({ note: '', vitals: { bp: '', temp: '', pulse: '', resp: '' } });
  const [dischargeForm, setDischargeForm] = useState({ notes: '', status: 'Recovered' });

  // Tabs
  const HeaderTabs = useMemo(() => (
    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg border border-slate-200 dark:border-slate-700">
        <button 
            onClick={() => setActiveMainTab('ward')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${activeMainTab === 'ward' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
        >
            <LayoutGrid size={14} />
            <span className="hidden sm:inline">{t('admissions_title')}</span>
        </button>
        <button 
            onClick={() => setActiveMainTab('history')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${activeMainTab === 'history' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
        >
            <History size={14} />
            <span className="hidden sm:inline">{t('operations_tab_history')}</span>
        </button>
    </div>
  ), [activeMainTab, t]);

  useHeader(t('admissions_title'), t('admissions_subtitle'), HeaderTabs);

  const loadWardData = async () => {
    setLoading(true);
    try {
      const [bedsData, admissionsData, patientsData, staffData] = await Promise.all([
        api.getBeds(),
        api.getActiveAdmissions(),
        api.getPatients(),
        api.getStaff()
      ]);
      setBeds(bedsData || []);
      setActiveAdmissions(admissionsData || []);
      setPatients(patientsData || []);
      setStaff(staffData || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const loadHistoryData = async () => {
    setHistoryLoading(true);
    try {
      const data = await api.getAdmissionsHistory();
      setHistoryAdmissions(data || []);
    } catch (e) { console.error(e); }
    finally { setHistoryLoading(false); }
  };

  useEffect(() => {
    if (activeMainTab === 'ward') loadWardData();
    else loadHistoryData();
  }, [activeMainTab]);

  const handleReserve = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    setProcessMessage('Processing admission...');
    try {
      await api.createAdmission({ ...reserveForm, bedId: selectedBed.id });
      setProcessStatus('success');
      loadWardData();
      setTimeout(() => { setReserveModalOpen(false); setProcessStatus('idle'); }, 1000);
    } catch (err: any) {
      setProcessStatus('error');
      setProcessMessage(err.response?.data?.error || 'Failed');
    }
  };

  const handleOpenReserve = (bed: any) => {
    setSelectedBed(bed);
    setReserveForm({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: bed.costPerDay, notes: '' });
    setReserveModalOpen(true);
  };

  const handleOpenCare = async (admission: any) => {
    setCareModalOpen(true);
    setCareTab('overview');
    try {
      const details = await api.getInpatientDetails(admission.id);
      setSelectedAdmission(details);
    } catch (e) { console.error(e); }
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAdmission) return;
    setProcessStatus('processing');
    setProcessMessage('Saving clinical note...');
    try {
      await api.addInpatientNote(selectedAdmission.id, { 
        note: noteForm.note, 
        vitals: noteForm.vitals, 
        doctorId: selectedAdmission.doctor_id 
      });
      const updated = await api.getInpatientDetails(selectedAdmission.id);
      setSelectedAdmission(updated);
      setNoteForm({ note: '', vitals: { bp: '', temp: '', pulse: '', resp: '' } });
      setProcessStatus('success');
      setTimeout(() => setProcessStatus('idle'), 500);
    } catch (e) {
      setProcessStatus('error');
      setProcessMessage('Failed to save note');
    }
  };

  const handleDischarge = async () => {
    if (!selectedAdmission) return;
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_discharge_title'),
      message: t('admissions_dialog_discharge_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Processing discharge...');
        try {
          await api.dischargePatient(selectedAdmission.id, dischargeForm);
          setProcessStatus('success');
          loadWardData();
          setCareModalOpen(false);
          setTimeout(() => setProcessStatus('idle'), 1000);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Discharge failed');
        }
      }
    });
  };

  return (
    <div className="space-y-6">
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <Loader2 className="w-12 h-12 text-primary-600 animate-spin mb-4" />}
            {processStatus === 'success' && <CheckCircle className="w-12 h-12 text-green-600 mb-4" />}
            {processStatus === 'error' && <XCircle className="w-12 h-12 text-red-600 mb-4" />}
            <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{t(processStatus === 'processing' ? 'processing' : processStatus === 'success' ? 'success' : 'error')}</h3>
            <p className="text-slate-500 dark:text-slate-400 mb-6">{processMessage}</p>
            {processStatus === 'error' && <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>}
          </div>
        </div>
      )}

      {activeMainTab === 'ward' && (
        loading ? (
          <LoadingSpinner text={t('admissions_loading')} />
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-in fade-in">
            {beds.map(bed => {
              const admission = activeAdmissions.find(a => a.bedId === bed.id);
              return (
                <Card key={bed.id} className={`relative overflow-hidden transition-all duration-200 border-l-4 ${bed.status === 'available' ? 'border-l-emerald-500' : bed.status === 'occupied' ? 'border-l-rose-500' : 'border-l-amber-500'}`}>
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex items-center gap-2">
                      <Bed size={20} className="text-slate-400"/>
                      <span className="font-black text-lg">{bed.roomNumber}</span>
                    </div>
                    <Badge color={bed.status === 'available' ? 'green' : bed.status === 'occupied' ? 'red' : 'yellow'}>
                      {t(`admissions_legend_${bed.status}`)}
                    </Badge>
                  </div>
                  <div className="text-xs text-slate-500 mb-4 font-medium uppercase tracking-wider">{bed.type} Ward</div>

                  {admission ? (
                    <div className="bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 mb-3">
                      <div className="font-bold text-sm text-slate-900 dark:text-white truncate">{admission.patientName}</div>
                      <div className="text-xs text-slate-500 mt-1 flex items-center gap-1"><User size={10}/> {admission.doctorName}</div>
                      <div className="text-xs text-slate-500 mt-1 flex items-center gap-1"><Clock size={10}/> {admission.stayDuration} days</div>
                    </div>
                  ) : (
                    <div className="h-[74px] flex items-center justify-center text-slate-300 text-xs italic bg-slate-50/50 dark:bg-slate-900/30 rounded-xl mb-3 border border-dashed border-slate-200 dark:border-slate-800">
