                ) : (
                  <>
                    <span>{t('login_button')}</span>
                    <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform rtl:group-hover:-translate-x-1" />
                  </>
                )}
              </button>
            </form>
          </div>

          <div className="bg-slate-50/50 dark:bg-slate-800/50 p-5 border-t border-slate-100 dark:border-slate-800">
            <p className="text-center text-[9px] text-slate-400 dark:text-slate-500 mb-3 font-bold uppercase tracking-widest">{t('login_quick_select_title')}</p>
            <div className="grid grid-cols-3 gap-y-4 gap-x-2">
              <QuickProfile role="admin" label={t('login_profile_admin')} icon={ShieldCheck} color="from-rose-500 to-red-600" />
              <QuickProfile role="doctor" label={t('staff_role_doctor')} icon={Stethoscope} color="from-blue-600 to-indigo-600" />
              <QuickProfile role="manager" label={t('login_profile_manager')} icon={LayoutDashboard} color="from-orange-500 to-amber-500" />
              <QuickProfile role="receptionist" label={t('login_profile_desk')} icon={UserIcon} color="from-blue-500 to-cyan-500" />
              <QuickProfile role="technician" label={t('login_profile_lab')} icon={Microscope} color="from-emerald-500 to-teal-500" />
              <QuickProfile role="accountant" label={t('login_profile_finance')} icon={CreditCard} color="from-violet-500 to-purple-500" />
            </div>
          </div>
        </div>

        <div className="mt-6 flex flex-col items-center gap-2">
           <div className="flex items-center gap-1.5 text-slate-400 dark:text-slate-600 text-[10px] font-bold uppercase tracking-widest opacity-70 hover:opacity-100 transition-opacity">
              <Database size={10} />
              <span>{t('login_footer_text')}</span>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  // Soft reload by forcing a state reset.
  // With MemoryRouter, we avoid touching window.location or history API.
  private handleReload = () => {
    this.setState({ hasError: false, error: null });
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Card, Button, Badge, Modal, Input, Textarea, Select, ConfirmationDialog, LoadingSpinner } from '../components/UI';
import { 
  Bed, User, Calendar, Activity, CheckCircle, FileText, AlertCircle, 
  Clock, LogOut, Plus, Search, DollarSign, Loader2, XCircle, 
  ChevronRight, X, Info, Save, Trash2, History, LayoutGrid, AlertTriangle
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';
import { useHeader } from '../context/HeaderContext';

export const Admissions = () => {
  const { t } = useTranslation();
  const { user: currentUser } = useAuth();

  const [activeMainTab, setActiveMainTab] = useState<'ward' | 'history'>('ward');

  const [beds, setBeds] = useState<any[]>([]);
  const [activeAdmissions, setActiveAdmissions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [patients, setPatients] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // History State
  const [historyAdmissions, setHistoryAdmissions] = useState<any[]>([]);
  const [historyLoading, setHistoryLoading] = useState(false);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  // Modals
  const [reserveModalOpen, setReserveModalOpen] = useState(false);
  const [careModalOpen, setCareModalOpen] = useState(false);

  const [selectedBed, setSelectedBed] = useState<any>(null);
  const [selectedAdmission, setSelectedAdmission] = useState<any>(null);

  // Forms
  const [reserveForm, setReserveForm] = useState({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: 0, notes: '' });
  const [careTab, setCareTab] = useState<'overview' | 'notes' | 'discharge'>('overview');
  const [noteForm, setNoteForm] = useState({ note: '', vitals: { bp: '', temp: '', pulse: '', resp: '' } });
  const [dischargeForm, setDischargeForm] = useState({ notes: '', status: 'Recovered' });

  // Group beds logic
  const bedsByType = useMemo(() => {
    const groups: Record<string, any[]> = {};
    beds.forEach(bed => {
      const type = bed.type || 'Unassigned';
      if (!groups[type]) groups[type] = [];
      groups[type].push(bed);
    });
    return groups;
  }, [beds]);

  // Tabs
  const HeaderTabs = useMemo(() => (
    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg border border-slate-200 dark:border-slate-700">
        <button 
            onClick={() => setActiveMainTab('ward')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${activeMainTab === 'ward' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
        >
            <LayoutGrid size={14} />
            <span className="hidden sm:inline">{t('admissions_title')}</span>
        </button>
        <button 
            onClick={() => setActiveMainTab('history')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${activeMainTab === 'history' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
        >
            <History size={14} />
            <span className="hidden sm:inline">{t('operations_tab_history')}</span>
        </button>
    </div>
  ), [activeMainTab, t]);

  useHeader(t('admissions_title'), t('admissions_subtitle'), HeaderTabs);

  const loadWardData = async () => {
    setLoading(true);
    try {
      const [bedsData, admissionsData, patientsData, staffData] = await Promise.all([
        api.getBeds(),
        api.getActiveAdmissions(),
        api.getPatients(),
        api.getStaff()
      ]);
      setBeds(bedsData || []);
      setActiveAdmissions(admissionsData || []);
      setPatients(patientsData || []);
      setStaff(staffData || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const loadHistoryData = async () => {
    setHistoryLoading(true);
    try {
      const data = await api.getAdmissionsHistory();
      setHistoryAdmissions(data || []);
    } catch (e) { console.error(e); }
    finally { setHistoryLoading(false); }
  };

  useEffect(() => {
    if (activeMainTab === 'ward') loadWardData();
    else loadHistoryData();
  }, [activeMainTab]);

  const handleReserve = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    setProcessMessage('Processing admission...');
    try {
      await api.createAdmission({ ...reserveForm, bedId: selectedBed.id });
      setProcessStatus('success');
      loadWardData();
      setTimeout(() => { setReserveModalOpen(false); setProcessStatus('idle'); }, 1000);
    } catch (err: any) {
      setProcessStatus('error');
      setProcessMessage(err.response?.data?.error || 'Failed');
    }
  };

  const handleOpenReserve = (bed: any) => {
    setSelectedBed(bed);
    setReserveForm({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: bed.costPerDay, notes: '' });
    setReserveModalOpen(true);
  };

  const handleOpenCare = async (admission: any) => {
    setCareModalOpen(true);
    setCareTab('overview');
    try {
      const details = await api.getInpatientDetails(admission.id);
      setSelectedAdmission(details);
    } catch (e) { console.error(e); }
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAdmission) return;
    setProcessStatus('processing');
    setProcessMessage('Saving clinical note...');
    try {
      await api.addInpatientNote(selectedAdmission.id, { 
        note: noteForm.note, 
        vitals: noteForm.vitals, 
        doctorId: selectedAdmission.doctor_id 
      });
      const updated = await api.getInpatientDetails(selectedAdmission.id);
      setSelectedAdmission(updated);
      setNoteForm({ note: '', vitals: { bp: '', temp: '', pulse: '', resp: '' } });
      setProcessStatus('success');
      setTimeout(() => setProcessStatus('idle'), 500);
    } catch (e) {
      setProcessStatus('error');
      setProcessMessage('Failed to save note');
    }
  };

  const handleDischarge = async () => {
    if (!selectedAdmission) return;
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_discharge_title'),
      message: t('admissions_dialog_discharge_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Processing discharge...');
        try {
          await api.dischargePatient(selectedAdmission.id, dischargeForm);
          setProcessStatus('success');
          loadWardData();
          setCareModalOpen(false);
          setTimeout(() => setProcessStatus('idle'), 1000);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Discharge failed');
        }
      }
    });
  };

  return (
    <div className="space-y-6">
      {/* Process Modal */}
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <Loader2 className="w-12 h-12 text-primary-600 animate-spin mb-4" />}
            {processStatus === 'success' && <CheckCircle className="w-12 h-12 text-green-600 mb-4" />}
            {processStatus === 'error' && <XCircle className="w-12 h-12 text-red-600 mb-4" />}
            <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{t(processStatus === 'processing' ? 'processing' : processStatus === 'success' ? 'success' : 'error')}</h3>
            <p className="text-slate-500 dark:text-slate-400 mb-6">{processMessage}</p>
            {processStatus === 'error' && <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>}
          </div>
        </div>
      )}

      {activeMainTab === 'ward' && (
        loading ? (
          <LoadingSpinner text={t('admissions_loading')} />
        ) : (
          <div className="space-y-8 animate-in fade-in">
            {Object.keys(bedsByType).length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <Bed size={48} className="mb-4 opacity-50"/>
                    <p className="font-medium">No beds configured.</p>
                </div>
            ) : (
                Object.entries(bedsByType).map(([type, typeBeds]) => (
                    <div key={type} className="space-y-4">
                        <div className="flex items-center gap-3 border-b border-slate-200 dark:border-slate-700 pb-2">
                            <h3 className="text-sm font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">{type} Ward</h3>
                            <Badge color="gray">{typeBeds.length} Beds</Badge>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {typeBeds.map(bed => {
                                const admission = activeAdmissions.find(a => a.bedId === bed.id);
                                return (
                                    <Card key={bed.id} className={`relative overflow-hidden transition-all duration-200 border-l-4 ${bed.status === 'available' ? 'border-l-emerald-500' : bed.status === 'occupied' ? 'border-l-rose-500' : 'border-l-amber-500'}`}>
                                    <div className="flex justify-between items-start mb-3">
                                        <div className="flex items-center gap-2">
                                        <Bed size={20} className="text-slate-400"/>
                                        <span className="font-black text-lg">{bed.roomNumber}</span>
                                        </div>
                                        <Badge color={bed.status === 'available' ? 'green' : bed.status === 'occupied' ? 'red' : 'yellow'}>
                                        {t(`admissions_legend_${bed.status}`)}
                                        </Badge>
                                    </div>
                                    <div className="text-xs text-slate-500 mb-4 font-medium uppercase tracking-wider">{bed.type} Ward</div>

                                    {admission ? (
                                        <div className="bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 mb-3">
                                        <div className="font-bold text-sm text-slate-900 dark:text-white truncate">{admission.patientName}</div>
                                        <div className="text-xs text-slate-500 mt-1 flex items-center gap-1"><User size={10}/> {admission.doctorName}</div>
                                        <div className="text-xs text-slate-500 mt-1 flex items-center gap-1"><Clock size={10}/> {admission.stayDuration} days</div>
                                        </div>
                                    ) : (
                                        <div className="h-[74px] flex items-center justify-center text-slate-300 text-xs italic bg-slate-50/50 dark:bg-slate-900/30 rounded-xl mb-3 border border-dashed border-slate-200 dark:border-slate-800">
                                        Empty Bed
                                        </div>
                                    )}

                                    {bed.status === 'available' ? (
                                        <Button size="sm" className="w-full" onClick={() => handleOpenReserve(bed)}>
                                        {t('admissions_bed_click_to_admit')}
                                        </Button>
                                    ) : admission ? (
                                        <Button size="sm" variant="outline" className="w-full" onClick={() => handleOpenCare(admission)}>
                                        {t('admissions_bed_manage')}
                                        </Button>
                                    ) : (
                                        <Button size="sm" variant="secondary" className="w-full" disabled>
                                        Maintenance
                                        </Button>
                                    )}
                                    </Card>
                                );
                            })}
                        </div>
                    </div>
                ))
            )}
          </div>
        )
      )}

      {/* History Tab */}
      {activeMainTab === 'history' && (
        <Card className="!p-0 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
              <thead className="bg-slate-50 dark:bg-slate-900">
                <tr>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Patient</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Bed</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Doctor</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Admitted</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Discharged</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Duration</th>
                </tr>
              </thead>
              <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-100 dark:divide-slate-700">
                {historyLoading ? (
                  <tr><td colSpan={6}><LoadingSpinner text="Loading history..." className="py-10"/></td></tr>
                ) : historyAdmissions.length === 0 ? (
                  <tr><td colSpan={6} className="text-center py-10 text-slate-400">No history found.</td></tr>
                ) : (
                  historyAdmissions.map(adm => (
                    <tr key={adm.id}>
                      <td className="px-6 py-4 font-bold text-sm text-slate-900 dark:text-white">{adm.patientName}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.roomNumber}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.doctorName}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{new Date(adm.entry_date).toLocaleDateString()}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.actual_discharge_date ? new Date(adm.actual_discharge_date).toLocaleDateString() : '-'}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.stayDuration} days</td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </Card>
      )}

      {/* Reserve Modal */}
      <Modal isOpen={reserveModalOpen} onClose={() => setReserveModalOpen(false)} title="Admit Patient">
        <form onSubmit={handleReserve} className="space-y-4">
          <div className="bg-slate-50 dark:bg-slate-900 p-3 rounded-lg text-sm border border-slate-100 dark:border-slate-800 mb-2">
            Selected Bed: <span className="font-bold">{selectedBed?.roomNumber}</span> ({selectedBed?.type}) - <span className="text-primary-600 font-bold">${selectedBed?.costPerDay}/day</span>
          </div>
          <Select label="Patient" value={reserveForm.patientId} onChange={e => setReserveForm({...reserveForm, patientId: e.target.value})} required>
            <option value="">Select Patient</option>
            {patients.map(p => <option key={p.id} value={p.id}>{p.fullName}</option>)}
          </Select>
          <Select label="Doctor" value={reserveForm.doctorId} onChange={e => setReserveForm({...reserveForm, doctorId: e.target.value})} required>
            <option value="">Select Doctor</option>
            {staff.filter(s => s.type === 'doctor').map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
          </Select>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Entry Date" type="date" value={reserveForm.entryDate} onChange={e => setReserveForm({...reserveForm, entryDate: e.target.value})} required />
            <Input label="Required Deposit ($)" type="number" value={reserveForm.deposit} onChange={e => setReserveForm({...reserveForm, deposit: parseFloat(e.target.value)})} required />
          </div>
          <Textarea label="Notes" value={reserveForm.notes} onChange={e => setReserveForm({...reserveForm, notes: e.target.value})} rows={2} />
          <Button type="submit" className="w-full">Confirm Admission</Button>
        </form>
      </Modal>

      {/* Care Modal */}
      <Modal isOpen={careModalOpen} onClose={() => setCareModalOpen(false)} title="Patient Care & Management">
        {selectedAdmission && (
          <div className="space-y-6">
            <div className="flex gap-2 border-b border-slate-200 dark:border-slate-700 pb-1">
              {['overview', 'notes', 'discharge'].map(tab => (
                <button
                  key={tab}
                  onClick={() => setCareTab(tab as any)}
                  className={`px-4 py-2 text-sm font-bold capitalize transition-colors ${careTab === tab ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  {tab}
                </button>
              ))}
            </div>

            {careTab === 'overview' && (
              <div className="space-y-4">
                <div className="p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800">
                  <h3 className="font-bold text-lg">{selectedAdmission.patientName}</h3>
                  <div className="text-sm text-slate-500 mt-1">
                    Admitted: {new Date(selectedAdmission.entry_date).toLocaleDateString()} • Dr. {selectedAdmission.doctorName}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <Card title="Vitals Trend" className="!p-4 bg-white shadow-sm border">
                    <div className="text-center text-slate-400 py-8 text-xs">Chart placeholder</div>
                  </Card>
                  <Card title="Financial" className="!p-4 bg-white shadow-sm border">
                    <div className="space-y-2">
                      <div className="flex justify-between text-sm"><span>Deposit</span><span className="font-mono font-bold text-green-600">${selectedAdmission.depositPaid || 0}</span></div>
                      <div className="flex justify-between text-sm"><span>Est. Total</span><span className="font-mono font-bold">${selectedAdmission.estimatedBill || 0}</span></div>
                    </div>
                  </Card>
                </div>
              </div>
            )}

            {careTab === 'notes' && (
              <div className="space-y-4">
                <form onSubmit={handleAddNote} className="p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 space-y-3">
                  <h4 className="font-bold text-sm">New Clinical Note</h4>
                  <div className="grid grid-cols-4 gap-2">
                    <Input placeholder="BP" value={noteForm.vitals.bp} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, bp: e.target.value}})} className="text-xs" />
                    <Input placeholder="Temp" value={noteForm.vitals.temp} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, temp: e.target.value}})} className="text-xs" />
                    <Input placeholder="Pulse" value={noteForm.vitals.pulse} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, pulse: e.target.value}})} className="text-xs" />
                    <Input placeholder="Resp" value={noteForm.vitals.resp} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, resp: e.target.value}})} className="text-xs" />
                  </div>
                  <Textarea placeholder="Observations, medication given, etc." value={noteForm.note} onChange={e => setNoteForm({...noteForm, note: e.target.value})} rows={3} required />
                  <div className="flex justify-end"><Button size="sm" type="submit">Add Note</Button></div>
                </form>
                <div className="space-y-3 max-h-60 overflow-y-auto">
                  {selectedAdmission.notes?.map((n: any) => (
                    <div key={n.id} className="p-3 border rounded-lg bg-white dark:bg-slate-800">
                      <div className="flex justify-between text-xs text-slate-500 mb-1">
                        <span>{new Date(n.created_at).toLocaleString()}</span>
                        <span className="font-bold">{n.doctorName}</span>
                      </div>
                      <p className="text-sm text-slate-800 dark:text-slate-200">{n.note}</p>
                      {n.vitals && (
                        <div className="mt-2 flex gap-3 text-xs font-mono text-slate-600 bg-slate-50 p-1 rounded">
                          {n.vitals.bp && <span>BP: {n.vitals.bp}</span>}
                          {n.vitals.temp && <span>T: {n.vitals.temp}</span>}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {careTab === 'discharge' && (
              <div className="space-y-4">
                <div className="bg-amber-50 text-amber-800 p-4 rounded-xl text-sm">
                  <AlertTriangle className="inline-block mr-2" size={16}/>
                  Discharging will finalize the bill and release the bed. Ensure all services are recorded.
                </div>
                <Select label="Discharge Status" value={dischargeForm.status} onChange={e => setDischargeForm({...dischargeForm, status: e.target.value})}>
                  <option value="Recovered">Recovered</option>
                  <option value="Transferred">Transferred</option>
                  <option value="Deceased">Deceased</option>
                  <option value="AMA">Against Medical Advice</option>
                </Select>
                <Textarea label="Discharge Summary" value={dischargeForm.notes} onChange={e => setDischargeForm({...dischargeForm, notes: e.target.value})} rows={4} />
                <Button variant="danger" className="w-full" onClick={handleDischarge}>Process Discharge</Button>
              </div>
            )}
          </div>
        )}
      </Modal>

      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message} />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Card, Button, Badge, Modal, Input, Textarea, Select, ConfirmationDialog, LoadingSpinner } from '../components/UI';
import { 
  Bed, User, Calendar, Activity, CheckCircle, FileText, AlertCircle, 
  Clock, LogOut, Plus, Search, DollarSign, Loader2, XCircle, 
  ChevronRight, X, Info, Save, Trash2, History, LayoutGrid, AlertTriangle
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';
import { useHeader } from '../context/HeaderContext';

export const Admissions = () => {
  const { t } = useTranslation();
  const { user: currentUser } = useAuth();

  const [activeMainTab, setActiveMainTab] = useState<'ward' | 'history'>('ward');

  const [beds, setBeds] = useState<any[]>([]);
  const [activeAdmissions, setActiveAdmissions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [patients, setPatients] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // History State
  const [historyAdmissions, setHistoryAdmissions] = useState<any[]>([]);
  const [historyLoading, setHistoryLoading] = useState(false);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  // Modals
  const [reserveModalOpen, setReserveModalOpen] = useState(false);
  const [careModalOpen, setCareModalOpen] = useState(false);

  const [selectedBed, setSelectedBed] = useState<any>(null);
  const [selectedAdmission, setSelectedAdmission] = useState<any>(null);

  // Forms
  const [reserveForm, setReserveForm] = useState({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: 0, notes: '' });
  const [careTab, setCareTab] = useState<'overview' | 'notes' | 'discharge'>('overview');
  const [noteForm, setNoteForm] = useState({ note: '', vitals: { bp: '', temp: '', pulse: '', resp: '' } });
  const [dischargeForm, setDischargeForm] = useState({ notes: '', status: 'Recovered' });

  // Group beds logic
  const bedsByType = useMemo<Record<string, any[]>>(() => {
    const groups: Record<string, any[]> = {};
    beds.forEach((bed: any) => {
      const type = bed.type || 'Unassigned';
      if (!groups[type]) groups[type] = [];
      groups[type].push(bed);
    });
    return groups;
  }, [beds]);

  // Tabs
  const HeaderTabs = useMemo(() => (
    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg border border-slate-200 dark:border-slate-700">
        <button 
            onClick={() => setActiveMainTab('ward')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${activeMainTab === 'ward' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
        >
            <LayoutGrid size={14} />
            <span className="hidden sm:inline">{t('admissions_title')}</span>
        </button>
        <button 
            onClick={() => setActiveMainTab('history')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${activeMainTab === 'history' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
        >
            <History size={14} />
            <span className="hidden sm:inline">{t('operations_tab_history')}</span>
        </button>
    </div>
  ), [activeMainTab, t]);

  useHeader(t('admissions_title'), t('admissions_subtitle'), HeaderTabs);

  const loadWardData = async () => {
    setLoading(true);
    try {
      const [bedsData, admissionsData, patientsData, staffData] = await Promise.all([
        api.getBeds(),
        api.getActiveAdmissions(),
        api.getPatients(),
        api.getStaff()
      ]);
      setBeds(bedsData || []);
      setActiveAdmissions(admissionsData || []);
      setPatients(patientsData || []);
      setStaff(staffData || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const loadHistoryData = async () => {
    setHistoryLoading(true);
    try {
      const data = await api.getAdmissionsHistory();
      setHistoryAdmissions(data || []);
    } catch (e) { console.error(e); }
    finally { setHistoryLoading(false); }
  };

  useEffect(() => {
    if (activeMainTab === 'ward') loadWardData();
    else loadHistoryData();
  }, [activeMainTab]);

  const handleReserve = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    setProcessMessage('Processing admission...');
    try {
      await api.createAdmission({ ...reserveForm, bedId: selectedBed.id });
      setProcessStatus('success');
      loadWardData();
      setTimeout(() => { setReserveModalOpen(false); setProcessStatus('idle'); }, 1000);
    } catch (err: any) {
      setProcessStatus('error');
      setProcessMessage(err.response?.data?.error || 'Failed');
    }
  };

  const handleOpenReserve = (bed: any) => {
    setSelectedBed(bed);
    setReserveForm({ patientId: '', doctorId: '', entryDate: new Date().toISOString().split('T')[0], deposit: bed.costPerDay, notes: '' });
    setReserveModalOpen(true);
  };

  const handleOpenCare = async (admission: any) => {
    setCareModalOpen(true);
    setCareTab('overview');
    try {
      const details = await api.getInpatientDetails(admission.id);
      setSelectedAdmission(details);
    } catch (e) { console.error(e); }
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAdmission) return;
    setProcessStatus('processing');
    setProcessMessage('Saving clinical note...');
    try {
      await api.addInpatientNote(selectedAdmission.id, { 
        note: noteForm.note, 
        vitals: noteForm.vitals, 
        doctorId: selectedAdmission.doctor_id 
      });
      const updated = await api.getInpatientDetails(selectedAdmission.id);
      setSelectedAdmission(updated);
      setNoteForm({ note: '', vitals: { bp: '', temp: '', pulse: '', resp: '' } });
      setProcessStatus('success');
      setTimeout(() => setProcessStatus('idle'), 500);
    } catch (e) {
      setProcessStatus('error');
      setProcessMessage('Failed to save note');
    }
  };

  const handleDischarge = async () => {
    if (!selectedAdmission) return;
    setConfirmState({
      isOpen: true,
      title: t('admissions_dialog_discharge_title'),
      message: t('admissions_dialog_discharge_message'),
      action: async () => {
        setProcessStatus('processing');
        setProcessMessage('Processing discharge...');
        try {
          await api.dischargePatient(selectedAdmission.id, dischargeForm);
          setProcessStatus('success');
          loadWardData();
          setCareModalOpen(false);
          setTimeout(() => setProcessStatus('idle'), 1000);
        } catch (e: any) {
          setProcessStatus('error');
          setProcessMessage(e.response?.data?.error || 'Discharge failed');
        }
      }
    });
  };

  return (
    <div className="space-y-6">
      {/* Process Modal */}
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <Loader2 className="w-12 h-12 text-primary-600 animate-spin mb-4" />}
            {processStatus === 'success' && <CheckCircle className="w-12 h-12 text-green-600 mb-4" />}
            {processStatus === 'error' && <XCircle className="w-12 h-12 text-red-600 mb-4" />}
            <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{t(processStatus === 'processing' ? 'processing' : processStatus === 'success' ? 'success' : 'error')}</h3>
            <p className="text-slate-500 dark:text-slate-400 mb-6">{processMessage}</p>
            {processStatus === 'error' && <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>}
          </div>
        </div>
      )}

      {activeMainTab === 'ward' && (
        loading ? (
          <LoadingSpinner text={t('admissions_loading')} />
        ) : (
          <div className="space-y-8 animate-in fade-in">
            {Object.keys(bedsByType).length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <Bed size={48} className="mb-4 opacity-50"/>
                    <p className="font-medium">No beds configured.</p>
                </div>
            ) : (
                Object.entries(bedsByType).map(([type, typeBeds]: [string, any[]]) => (
                    <div key={type} className="space-y-4">
                        <div className="flex items-center gap-3 border-b border-slate-200 dark:border-slate-700 pb-2">
                            <h3 className="text-sm font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">{type} Ward</h3>
                            <Badge color="gray">{typeBeds.length} Beds</Badge>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {typeBeds.map((bed: any) => {
                                const admission = activeAdmissions.find((a: any) => a.bedId === bed.id);
                                return (
                                    <Card key={bed.id} className={`relative overflow-hidden transition-all duration-200 border-l-4 ${bed.status === 'available' ? 'border-l-emerald-500' : bed.status === 'occupied' ? 'border-l-rose-500' : 'border-l-amber-500'}`}>
                                    <div className="flex justify-between items-start mb-3">
                                        <div className="flex items-center gap-2">
                                        <Bed size={20} className="text-slate-400"/>
                                        <span className="font-black text-lg">{bed.roomNumber}</span>
                                        </div>
                                        <Badge color={bed.status === 'available' ? 'green' : bed.status === 'occupied' ? 'red' : 'yellow'}>
                                        {t(`admissions_legend_${bed.status}`)}
                                        </Badge>
                                    </div>
                                    <div className="text-xs text-slate-500 mb-4 font-medium uppercase tracking-wider">{bed.type} Ward</div>

                                    {admission ? (
                                        <div className="bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800 mb-3">
                                        <div className="font-bold text-sm text-slate-900 dark:text-white truncate">{admission.patientName}</div>
                                        <div className="text-xs text-slate-500 mt-1 flex items-center gap-1"><User size={10}/> {admission.doctorName}</div>
                                        <div className="text-xs text-slate-500 mt-1 flex items-center gap-1"><Clock size={10}/> {admission.stayDuration} days</div>
                                        </div>
                                    ) : (
                                        <div className="h-[74px] flex items-center justify-center text-slate-300 text-xs italic bg-slate-50/50 dark:bg-slate-900/30 rounded-xl mb-3 border border-dashed border-slate-200 dark:border-slate-800">
                                        Empty Bed
                                        </div>
                                    )}

                                    {bed.status === 'available' ? (
                                        <Button size="sm" className="w-full" onClick={() => handleOpenReserve(bed)}>
                                        {t('admissions_bed_click_to_admit')}
                                        </Button>
                                    ) : admission ? (
                                        <Button size="sm" variant="outline" className="w-full" onClick={() => handleOpenCare(admission)}>
                                        {t('admissions_bed_manage')}
                                        </Button>
                                    ) : (
                                        <Button size="sm" variant="secondary" className="w-full" disabled>
                                        Maintenance
                                        </Button>
                                    )}
                                    </Card>
                                );
                            })}
                        </div>
                    </div>
                ))
            )}
          </div>
        )
      )}

      {/* History Tab */}
      {activeMainTab === 'history' && (
        <Card className="!p-0 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
              <thead className="bg-slate-50 dark:bg-slate-900">
                <tr>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Patient</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Bed</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Doctor</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Admitted</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Discharged</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Duration</th>
                </tr>
              </thead>
              <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-100 dark:divide-slate-700">
                {historyLoading ? (
                  <tr><td colSpan={6}><LoadingSpinner text="Loading history..." className="py-10"/></td></tr>
                ) : historyAdmissions.length === 0 ? (
                  <tr><td colSpan={6} className="text-center py-10 text-slate-400">No history found.</td></tr>
                ) : (
                  historyAdmissions.map(adm => (
                    <tr key={adm.id}>
                      <td className="px-6 py-4 font-bold text-sm text-slate-900 dark:text-white">{adm.patientName}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.roomNumber}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.doctorName}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{new Date(adm.entry_date).toLocaleDateString()}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.actual_discharge_date ? new Date(adm.actual_discharge_date).toLocaleDateString() : '-'}</td>
                      <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">{adm.stayDuration} days</td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </Card>
      )}

      {/* Reserve Modal */}
      <Modal isOpen={reserveModalOpen} onClose={() => setReserveModalOpen(false)} title="Admit Patient">
        <form onSubmit={handleReserve} className="space-y-4">
          <div className="bg-slate-50 dark:bg-slate-900 p-3 rounded-lg text-sm border border-slate-100 dark:border-slate-800 mb-2">
            Selected Bed: <span className="font-bold">{selectedBed?.roomNumber}</span> ({selectedBed?.type}) - <span className="text-primary-600 font-bold">${selectedBed?.costPerDay}/day</span>
          </div>
          <Select label="Patient" value={reserveForm.patientId} onChange={e => setReserveForm({...reserveForm, patientId: e.target.value})} required>
            <option value="">Select Patient</option>
            {patients.map(p => <option key={p.id} value={p.id}>{p.fullName}</option>)}
          </Select>
          <Select label="Doctor" value={reserveForm.doctorId} onChange={e => setReserveForm({...reserveForm, doctorId: e.target.value})} required>
            <option value="">Select Doctor</option>
            {staff.filter(s => s.type === 'doctor').map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
          </Select>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Entry Date" type="date" value={reserveForm.entryDate} onChange={e => setReserveForm({...reserveForm, entryDate: e.target.value})} required />
            <Input label="Required Deposit ($)" type="number" value={reserveForm.deposit} onChange={e => setReserveForm({...reserveForm, deposit: parseFloat(e.target.value)})} required />
          </div>
          <Textarea label="Notes" value={reserveForm.notes} onChange={e => setReserveForm({...reserveForm, notes: e.target.value})} rows={2} />
          <Button type="submit" className="w-full">Confirm Admission</Button>
        </form>
      </Modal>

      {/* Care Modal */}
      <Modal isOpen={careModalOpen} onClose={() => setCareModalOpen(false)} title="Patient Care & Management">
        {selectedAdmission && (
          <div className="space-y-6">
            <div className="flex gap-2 border-b border-slate-200 dark:border-slate-700 pb-1">
              {['overview', 'notes', 'discharge'].map(tab => (
                <button
                  key={tab}
                  onClick={() => setCareTab(tab as any)}
                  className={`px-4 py-2 text-sm font-bold capitalize transition-colors ${careTab === tab ? 'text-primary-600 border-b-2 border-primary-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  {tab}
                </button>
              ))}
            </div>

            {careTab === 'overview' && (
              <div className="space-y-4">
                <div className="p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800">
                  <h3 className="font-bold text-lg">{selectedAdmission.patientName}</h3>
                  <div className="text-sm text-slate-500 mt-1">
                    Admitted: {new Date(selectedAdmission.entry_date).toLocaleDateString()} • Dr. {selectedAdmission.doctorName}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <Card title="Vitals Trend" className="!p-4 bg-white shadow-sm border">
                    <div className="text-center text-slate-400 py-8 text-xs">Chart placeholder</div>
                  </Card>
                  <Card title="Financial" className="!p-4 bg-white shadow-sm border">
                    <div className="space-y-2">
                      <div className="flex justify-between text-sm"><span>Deposit</span><span className="font-mono font-bold text-green-600">${selectedAdmission.depositPaid || 0}</span></div>
                      <div className="flex justify-between text-sm"><span>Est. Total</span><span className="font-mono font-bold">${selectedAdmission.estimatedBill || 0}</span></div>
                    </div>
                  </Card>
                </div>
              </div>
            )}

            {careTab === 'notes' && (
              <div className="space-y-4">
                <form onSubmit={handleAddNote} className="p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 space-y-3">
                  <h4 className="font-bold text-sm">New Clinical Note</h4>
                  <div className="grid grid-cols-4 gap-2">
                    <Input placeholder="BP" value={noteForm.vitals.bp} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, bp: e.target.value}})} className="text-xs" />
                    <Input placeholder="Temp" value={noteForm.vitals.temp} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, temp: e.target.value}})} className="text-xs" />
                    <Input placeholder="Pulse" value={noteForm.vitals.pulse} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, pulse: e.target.value}})} className="text-xs" />
                    <Input placeholder="Resp" value={noteForm.vitals.resp} onChange={e => setNoteForm({...noteForm, vitals: {...noteForm.vitals, resp: e.target.value}})} className="text-xs" />
                  </div>
                  <Textarea placeholder="Observations, medication given, etc." value={noteForm.note} onChange={e => setNoteForm({...noteForm, note: e.target.value})} rows={3} required />
                  <div className="flex justify-end"><Button size="sm" type="submit">Add Note</Button></div>
                </form>
                <div className="space-y-3 max-h-60 overflow-y-auto">
                  {selectedAdmission.notes?.map((n: any) => (
                    <div key={n.id} className="p-3 border rounded-lg bg-white dark:bg-slate-800">
                      <div className="flex justify-between text-xs text-slate-500 mb-1">
                        <span>{new Date(n.created_at).toLocaleString()}</span>
                        <span className="font-bold">{n.doctorName}</span>
                      </div>
                      <p className="text-sm text-slate-800 dark:text-slate-200">{n.note}</p>
                      {n.vitals && (
                        <div className="mt-2 flex gap-3 text-xs font-mono text-slate-600 bg-slate-50 p-1 rounded">
                          {n.vitals.bp && <span>BP: {n.vitals.bp}</span>}
                          {n.vitals.temp && <span>T: {n.vitals.temp}</span>}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {careTab === 'discharge' && (
              <div className="space-y-4">
                <div className="bg-amber-50 text-amber-800 p-4 rounded-xl text-sm">
                  <AlertTriangle className="inline-block mr-2" size={16}/>
                  Discharging will finalize the bill and release the bed. Ensure all services are recorded.
                </div>
                <Select label="Discharge Status" value={dischargeForm.status} onChange={e => setDischargeForm({...dischargeForm, status: e.target.value})}>
                  <option value="Recovered">Recovered</option>
                  <option value="Transferred">Transferred</option>
                  <option value="Deceased">Deceased</option>
                  <option value="AMA">Against Medical Advice</option>
                </Select>
                <Textarea label="Discharge Summary" value={dischargeForm.notes} onChange={e => setDischargeForm({...dischargeForm, notes: e.target.value})} rows={4} />
                <Button variant="danger" className="w-full" onClick={handleDischarge}>Process Discharge</Button>
              </div>
            )}
          </div>
        )}
      </Modal>

      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message} />
    </div>
  );
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  // Soft reload by forcing a state reset.
  // With MemoryRouter, we avoid touching window.location or history API.
  private handleReload = () => {
    this.setState({ hasError: false, error: null });
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}
